"use client";

import { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";

export const FootballMode = () => {
    const [outcome, setOutcome] = useState<"none" | "goal" | "miss">("none");

    const handleShoot = () => {
        // Random outcome for demonstration
        const result = Math.random() > 0.5 ? "goal" : "miss";
        setOutcome(result);
    };

    return (
        <div className="flex flex-col items-center justify-center p-8 w-full max-w-4xl mx-auto">
            <h2 className="text-3xl font-serif text-white mb-8">The Penalty Shootout</h2>

            <div className="relative h-96 w-full max-w-2xl bg-gradient-to-b from-green-900/20 to-green-900/5 rounded-lg border border-white/10 flex items-end justify-center overflow-hidden">

                {/* Goal Post */}
                <div className="absolute top-10 left-1/2 -translate-x-1/2 w-2/3 h-40 border-t-4 border-x-4 border-white/30" />

                {outcome === "none" && (
                    <motion.button
                        whileHover={{ scale: 1.1 }}
                        whileTap={{ scale: 0.9 }}
                        onClick={handleShoot}
                        className="mb-12 h-16 w-16 rounded-full bg-white border-4 border-black shadow-xl z-10"
                    >
                        <span className="sr-only">Shoot</span>
                    </motion.button>
                )}

                <AnimatePresence>
                    {outcome !== "none" && (
                        <motion.div
                            initial={{ opacity: 0, scale: 0.5, y: 50 }}
                            animate={{ opacity: 1, scale: 1, y: 0 }}
                            className="absolute inset-0 z-20 flex flex-col items-center justify-center bg-black/80 backdrop-blur-md p-8 text-center"
                        >
                            {outcome === "goal" ? (
                                <>
                                    <h3 className="text-4xl font-serif text-green-400 mb-4">GOAL!</h3>
                                    <p className="text-white text-lg">Lead Developer at TechCorp</p>
                                    <p className="text-neutral-400 text-sm mt-2">Delivered complex systems under pressure.</p>
                                </>
                            ) : (
                                <>
                                    <h3 className="text-4xl font-serif text-red-400 mb-4">SAVED.</h3>
                                    <p className="text-white text-lg">Failed Startup Attempt 2024</p>
                                    <p className="text-neutral-400 text-sm mt-2">"Learned market fit the hard way. Still standing."</p>
                                </>
                            )}
                            <button
                                onClick={() => setOutcome("none")}
                                className="mt-8 px-6 py-2 bg-white/10 hover:bg-white/20 rounded-full text-white transition-colors"
                            >
                                Shoot Again
                            </button>
                        </motion.div>
                    )}
                </AnimatePresence>
            </div>
        </div>
    );
};
