"use client";

import { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";

export const ChessMode = () => {
    const [revealed, setRevealed] = useState(false);

    return (
        <div className="flex flex-col items-center justify-center p-8 w-full max-w-4xl mx-auto">
            <h2 className="text-3xl font-serif text-white mb-8">The Brilliant Move</h2>

            <div className="relative aspect-square w-full max-w-md bg-white/5 rounded-lg border border-white/10 p-4">
                {/* Simplified Chess Board Visual */}
                <div className="grid grid-cols-8 grid-rows-8 h-full w-full border border-white/20">
                    {[...Array(64)].map((_, i) => {
                        const isBlack = Math.floor(i / 8) % 2 === 0 ? i % 2 === 1 : i % 2 === 0;
                        return (
                            <div key={i} className={`${isBlack ? 'bg-white/10' : 'bg-transparent'} relative`} />
                        )
                    })}
                </div>

                {/* Interaction Overlay */}
                {!revealed ? (
                    <motion.button
                        whileHover={{ scale: 1.05 }}
                        whileTap={{ scale: 0.95 }}
                        onClick={() => setRevealed(true)}
                        className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 bg-blue-500/20 text-blue-300 px-6 py-3 rounded-full border border-blue-500/50 backdrop-blur-xl font-mono animate-pulse"
                    >
                        PLAY Ng5!!
                    </motion.button>
                ) : (
                    <AnimatePresence>
                        <motion.div
                            initial={{ opacity: 0, scale: 0.8 }}
                            animate={{ opacity: 1, scale: 1 }}
                            className="absolute inset-0 z-10 flex flex-col items-center justify-center bg-black/90 backdrop-blur-md rounded-lg p-6 text-center"
                        >
                            <h3 className="text-2xl font-serif text-yellow-400 mb-2">Victory!</h3>
                            <p className="text-neutral-300 mb-4">
                                3rd Place at Mumbai Hacks
                            </p>
                            <div className="text-sm text-neutral-500 font-mono">
                                "Calculated risk is the key to durability."
                            </div>
                            <button
                                onClick={() => setRevealed(false)}
                                className="mt-6 text-xs text-neutral-400 hover:text-white underline"
                            >
                                Replay
                            </button>
                        </motion.div>
                    </AnimatePresence>
                )}
            </div>
        </div>
    );
};
